# Error
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class Error(Exception):
    pass

_UniffiTempError = Error

class Error:  # type: ignore
    class DuplicateNode(_UniffiTempError):
        def __init__(self, *values):
            if len(values) != 1:
                raise TypeError(f"Expected 1 arguments, found {len(values)}")
            if not isinstance(values[0], str):
                raise TypeError(f"unexpected type for tuple element 0 - expected 'str', got '{type(values[0])}'")
            super().__init__(", ".join(map(repr, values)))
            self._values = values

        def __getitem__(self, index):
            return self._values[index]

        def __repr__(self):
            return "Error.DuplicateNode({})".format(str(self))
    _UniffiTempError.DuplicateNode = DuplicateNode # type: ignore
    class NoSuchNode(_UniffiTempError):
        def __init__(self, *values):
            if len(values) != 1:
                raise TypeError(f"Expected 1 arguments, found {len(values)}")
            if not isinstance(values[0], str):
                raise TypeError(f"unexpected type for tuple element 0 - expected 'str', got '{type(values[0])}'")
            super().__init__(", ".join(map(repr, values)))
            self._values = values

        def __getitem__(self, index):
            return self._values[index]

        def __repr__(self):
            return "Error.NoSuchNode({})".format(str(self))
    _UniffiTempError.NoSuchNode = NoSuchNode # type: ignore
    class UnparseableCreds(_UniffiTempError):
        def __init__(self):
            pass

        def __repr__(self):
            return "Error.UnparseableCreds({})".format(str(self))
    _UniffiTempError.UnparseableCreds = UnparseableCreds # type: ignore
    class PhraseCorrupted(_UniffiTempError):
        def __init__(self):
            pass

        def __repr__(self):
            return "Error.PhraseCorrupted({})".format(str(self))
    _UniffiTempError.PhraseCorrupted = PhraseCorrupted # type: ignore
    class Rpc(_UniffiTempError):
        def __init__(self, *values):
            if len(values) != 1:
                raise TypeError(f"Expected 1 arguments, found {len(values)}")
            if not isinstance(values[0], str):
                raise TypeError(f"unexpected type for tuple element 0 - expected 'str', got '{type(values[0])}'")
            super().__init__(", ".join(map(repr, values)))
            self._values = values

        def __getitem__(self, index):
            return self._values[index]

        def __repr__(self):
            return "Error.Rpc({})".format(str(self))
    _UniffiTempError.Rpc = Rpc # type: ignore
    class Argument(_UniffiTempError):
        def __init__(self, *values):
            if len(values) != 2:
                raise TypeError(f"Expected 2 arguments, found {len(values)}")
            if not isinstance(values[0], str):
                raise TypeError(f"unexpected type for tuple element 0 - expected 'str', got '{type(values[0])}'")
            if not isinstance(values[1], str):
                raise TypeError(f"unexpected type for tuple element 1 - expected 'str', got '{type(values[1])}'")
            super().__init__(", ".join(map(repr, values)))
            self._values = values

        def __getitem__(self, index):
            return self._values[index]

        def __repr__(self):
            return "Error.Argument({})".format(str(self))
    _UniffiTempError.Argument = Argument # type: ignore
    class Other(_UniffiTempError):
        def __init__(self, *values):
            if len(values) != 1:
                raise TypeError(f"Expected 1 arguments, found {len(values)}")
            if not isinstance(values[0], str):
                raise TypeError(f"unexpected type for tuple element 0 - expected 'str', got '{type(values[0])}'")
            super().__init__(", ".join(map(repr, values)))
            self._values = values

        def __getitem__(self, index):
            return self._values[index]

        def __repr__(self):
            return "Error.Other({})".format(str(self))
    _UniffiTempError.Other = Other # type: ignore

Error = _UniffiTempError # type: ignore
del _UniffiTempError


class _UniffiConverterTypeError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return Error.DuplicateNode(
                _UniffiConverterString.read(buf),
            )
        if variant == 2:
            return Error.NoSuchNode(
                _UniffiConverterString.read(buf),
            )
        if variant == 3:
            return Error.UnparseableCreds(
            )
        if variant == 4:
            return Error.PhraseCorrupted(
            )
        if variant == 5:
            return Error.Rpc(
                _UniffiConverterString.read(buf),
            )
        if variant == 6:
            return Error.Argument(
                _UniffiConverterString.read(buf),
                _UniffiConverterString.read(buf),
            )
        if variant == 7:
            return Error.Other(
                _UniffiConverterString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, Error.DuplicateNode):
            _UniffiConverterString.check_lower(value._values[0])
            return
        if isinstance(value, Error.NoSuchNode):
            _UniffiConverterString.check_lower(value._values[0])
            return
        if isinstance(value, Error.UnparseableCreds):
            return
        if isinstance(value, Error.PhraseCorrupted):
            return
        if isinstance(value, Error.Rpc):
            _UniffiConverterString.check_lower(value._values[0])
            return
        if isinstance(value, Error.Argument):
            _UniffiConverterString.check_lower(value._values[0])
            _UniffiConverterString.check_lower(value._values[1])
            return
        if isinstance(value, Error.Other):
            _UniffiConverterString.check_lower(value._values[0])
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, Error.DuplicateNode):
            buf.write_i32(1)
            _UniffiConverterString.write(value._values[0], buf)
        if isinstance(value, Error.NoSuchNode):
            buf.write_i32(2)
            _UniffiConverterString.write(value._values[0], buf)
        if isinstance(value, Error.UnparseableCreds):
            buf.write_i32(3)
        if isinstance(value, Error.PhraseCorrupted):
            buf.write_i32(4)
        if isinstance(value, Error.Rpc):
            buf.write_i32(5)
            _UniffiConverterString.write(value._values[0], buf)
        if isinstance(value, Error.Argument):
            buf.write_i32(6)
            _UniffiConverterString.write(value._values[0], buf)
            _UniffiConverterString.write(value._values[1], buf)
        if isinstance(value, Error.Other):
            buf.write_i32(7)
            _UniffiConverterString.write(value._values[0], buf)





class InputType:
    """
    The result of parsing user input.
    """

    def __init__(self):
        raise RuntimeError("InputType cannot be instantiated directly")

    # Each enum variant is a nested class of the enum itself.
    class BOLT11:
        """
        A BOLT11 Lightning invoice.
        """

        invoice: "ParsedInvoice"

        def __init__(self,invoice: "ParsedInvoice"):
            self.invoice = invoice

        def __str__(self):
            return "InputType.BOLT11(invoice={})".format(self.invoice)

        def __eq__(self, other):
            if not other.is_BOLT11():
                return False
            if self.invoice != other.invoice:
                return False
            return True
    
    class NODE_ID:
        """
        A Lightning node public key (66 hex characters, 33 bytes compressed).
        """

        node_id: "str"

        def __init__(self,node_id: "str"):
            self.node_id = node_id

        def __str__(self):
            return "InputType.NODE_ID(node_id={})".format(self.node_id)

        def __eq__(self, other):
            if not other.is_NODE_ID():
                return False
            if self.node_id != other.node_id:
                return False
            return True
    
    

    # For each variant, we have `is_NAME` and `is_name` methods for easily checking
    # whether an instance is that variant.
    def is_BOLT11(self) -> bool:
        return isinstance(self, InputType.BOLT11)
    def is_bolt11(self) -> bool:
        return isinstance(self, InputType.BOLT11)
    def is_NODE_ID(self) -> bool:
        return isinstance(self, InputType.NODE_ID)
    def is_node_id(self) -> bool:
        return isinstance(self, InputType.NODE_ID)
    

# Now, a little trick - we make each nested variant class be a subclass of the main
# enum class, so that method calls and instance checks etc will work intuitively.
# We might be able to do this a little more neatly with a metaclass, but this'll do.
InputType.BOLT11 = type("InputType.BOLT11", (InputType.BOLT11, InputType,), {})  # type: ignore
InputType.NODE_ID = type("InputType.NODE_ID", (InputType.NODE_ID, InputType,), {})  # type: ignore




class _UniffiConverterTypeInputType(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return InputType.BOLT11(
                _UniffiConverterTypeParsedInvoice.read(buf),
            )
        if variant == 2:
            return InputType.NODE_ID(
                _UniffiConverterString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value.is_BOLT11():
            _UniffiConverterTypeParsedInvoice.check_lower(value.invoice)
            return
        if value.is_NODE_ID():
            _UniffiConverterString.check_lower(value.node_id)
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value.is_BOLT11():
            buf.write_i32(1)
            _UniffiConverterTypeParsedInvoice.write(value.invoice, buf)
        if value.is_NODE_ID():
            buf.write_i32(2)
            _UniffiConverterString.write(value.node_id, buf)







